E_NM,SIGNUP_SUB_CATEGORY_XFR.SIGNUP_SUB_CATEGORY_NAME XFR_SGNP_SUB_CAT_NM,SIGNUP_XFR.signup_number XFR_SGNP_NBR,SIGNUP_XFR.SIGNUP_SUBTYPE_AGREEMENT_NAME XFR_SGNP_STYPE_AGR_NM,MASTER_CONTRACT_XFR.CONTRACT_NUMBER XFR_CTR_NBR,CONTRACT_DETAIL_XFR.CONTRACT_SUFFIX_NUMBER XFR_CTR_SFX_NBR,CONTRACT_DETAIL.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_DETAIL.CREATION_DATE CRE_DT,CONTRACT_DETAIL.CREATION_USER_NAME CRE_USER_NM,CONTRACT_DETAIL.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_DETAIL.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,CONTRACT_DETAIL.supplemental_contract_suffix_identification SUPL_CTR_SFX_ID,MASTER_CONTRACT.op,2 AS TBL_PRIORITYFROM "fsa-{env}-ccms-cdc".MASTER_CONTRACTJOIN "fsa-{env}-ccms-cdc".CONTRACT_DETAIL CONTRACT_DETAIL ON (MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP SIGNUP ON (SIGNUP.SIGNUP_IDENTIFIER = MASTER_CONTRACT.SIGNUP_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_TYPE SIGNUP_TYPE ON (SIGNUP_TYPE.SIGNUP_TYPE_CODE = SIGNUP.SIGNUP_TYPE_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY SIGNUP_SUB_CATEGORY ON (SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_DETAIL CONTRACT_DETAIL_PR ON (CONTRACT_DETAIL.PRIOR_CONTRACT_DETAIL_IDENTIFIER = CONTRACT_DETAIL_PR.CONTRACT_DETAIL_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".MASTER_CONTRACT MASTER_CONTRACT_PR ON (CONTRACT_DETAIL_PR.CONTRACT_IDENTIFIER = MASTER_CONTRACT_PR.CONTRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP SIGNUP_PR ON (SIGNUP_PR.SIGNUP_IDENTIFIER = MASTER_CONTRACT_PR.SIGNUP_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_TYPE SIGNUP_TYPE_PR ON (SIGNUP_TYPE_PR.SIGNUP_TYPE_CODE = SIGNUP_PR.SIGNUP_TYPE_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY SIGNUP_SUB_CATEGORY_PR ON (SIGNUP_SUB_CATEGORY_PR.SIGNUP_SUB_CATEGORY_CODE = SIGNUP_PR.SIGNUP_SUB_CATEGORY_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_DETAIL CONTRACT_DETAIL_XFR ON (CONT