IGNUP_XFR.SIGNUP_TYPE_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY SIGNUP_SUB_CATEGORY_XFR ON (SIGNUP_SUB_CATEGORY_XFR.SIGNUP_SUB_CATEGORY_CODE = SIGNUP_XFR.SIGNUP_SUB_CATEGORY_CODE)WHERE SIGNUP_TYPE.op <> 'D'UNIONSELECT MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP.signup_number SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAME SGNP_STYPE_AGR_NM,MASTER_CONTRACT.CONTRACT_NUMBER CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,CONTRACT_DETAIL.CONTRACT_ACTIVITY_TYPE_CODE CTR_ACTV_TYPE_CD,CONTRACT_DETAIL.PRIOR_CONTRACT_DETAIL_IDENTIFIER PR_CTR_DET_ID,CONTRACT_DETAIL.CONTRACT_IDENTIFIER CTR_ID,CONTRACT_DETAIL.CONTRACT_DESCRIPTION CTR_DESC,CONTRACT_DETAIL.EFFECTIVE_START_DATE EFF_STRT_DT,CONTRACT_DETAIL.EFFECTIVE_END_DATE EFF_END_DT,CONTRACT_DETAIL.APPROVED_DATE APRV_DT,CONTRACT_DETAIL.OTHER_ACTIVITY_REASON_DESCRIPTION OT_ACTV_RSN_DESC,CONTRACT_DETAIL.TRANSFER_CONTRACT_DETAIL_IDENTIFIER XFR_CTR_DET_ID,CONTRACT_DETAIL.PAYMENT_CONTRACT_SUFFIX_NUMBER PYMT_CTR_SFX_NBR,CONTRACT_DETAIL.PRACTICE_MAINTENANCE_RESPONSIBILITY_CODE PRAC_MNT_RESP_CD,CONTRACT_DETAIL.CONTRACT_ACREAGE CTR_ACRG,CONTRACT_DETAIL.PAYABLE_ACREAGE PYBL_ACRG,CONTRACT_DETAIL.EXPIRED_ACREAGE EXPR_ACRG,CONTRACT_DETAIL.PRODUCER_SIGNED_DATE PRDR_SGN_DT,CONTRACT_DETAIL.CP0_DOCUMENT_UPDATE_RECEIVED_INDICATOR CP0_DOC_UPD_RCV_IND,CONTRACT_DETAIL.forestry_services_responsibilities_completed_code FRST_SVC_RESP_CPLT_CD,CONTRACT_DETAIL.ANNUAL_WEIGHTED_AVERAGE_MAINTENANCE_AMOUNT_PER_ACRE ANL_WT_AVG_MNT_AMT_PER_ACRE,CONTRACT_DETAIL.ANNUAL_WEIGHTED_AVERAGE_SOIL_RENTAL_AMOUNT_PER_ACRE ANL_WT_AVG_SOIL_RNT_AMT_ACRE,CONTRACT_DETAIL.MIGRATION_REFERENCE_IDENTIFICATION MIGR_REF_ID,CONTRACT_DETAIL.ANNUAL_RENTAL_AMOUNT_PER_ACRE ANL_RNT_AMT_PER_ACRE,CONTRACT_DETAIL.Contract_Migration_Code CTR_MIGR_CD,CONTRACT_DETAIL.CONTRACT_CORRECTION_INDICATOR CTR_COR_IND,CONTRACT_DETAIL.MANUAL_RATE_CALCULATION_INDICATOR MNL_RT_CALC_IND,CONTRACT_DETAIL.Contract_Annual_Payment_Amount CTR_ANL_PYMT_AMT,CONTRACT_DETAIL.ANNUAL_WEIGHTED_AVERAGE_INCENTIVE_AMOUNT_PER_ACRE ANL_WT_AVG_INCTV_AMT_ACRE,CONTRACT_DETAIL.ANNUAL_MAXIMUM_PAYMENT_AMOUNT_PER_ACRE ANL_MAX_PYMT_AMT_PER_ACRE,CONTRACT_DETAIL.dafp_approved_date DAFP_APRV_DT,CONTRACT_DETAIL.NOTIFICATION_LETTER_SENT_DATE NTFY_LTR_SENT_DT,CONTRACT_DETAIL.VALID_CONTRACT_INDICATOR VLD_CTR_INDICAOR,CONTRACT_DETAIL.INVALID_CONTRACT_DATE IVLD_CTR_DT,MASTER_CONTRACT_PR.ADMINISTRATIVE_STATE_FSA_CODE PR_ADM_ST_FSA_CD,MASTER_CONTRACT_PR.ADMINISTRATIVE_COUNTY_FSA_CODE PR_ADM_CNTY_FSA_CD,SIGNUP_TYPE_PR.SIGNUP_TYPE_NAME PR_SGNP_TYPE_NM,SIGNUP_SUB_CATEGORY_PR.SIGNUP_SUB_CATEGORY_NAME PR_SGNP_SUB_CAT_NM,SIGNUP_PR.signup_number PR_SGNP_NBR,SIGNUP_PR.SIGNUP_SUBTYPE_AGREEMENT_NAME PR_SGNP_STYPE_AGR_NM,MASTER_CONTRACT_PR.CONTRACT_NUMBER PR_CTR_NBR,CONTRACT_DETAIL_PR.CONTRACT_SUFFIX_NUMBER PR_CTR_SFX_NBR,MASTER_CONTRACT_XFR.ADMINISTRATIVE_STATE_FSA_CODE XFR_ADM_ST_FSA_CD,MASTER_CONTRACT_XFR.ADMINISTRATIVE_COUNTY_FSA_CODE XFR_ADM_CNTY_FSA_CD,SIGNUP_TYPE_XFR.SIGNUP_TYPE_NAME XFR_SGNP_TYPE_NM,SIGNUP_SUB_CATEGORY_XFR.SIGNUP_SUB_CATEGORY_NAME XFR_SGNP_SUB_CAT_NM,SIGNUP_XFR.signup_number XFR_SGNP_NBR,SIGNUP_XFR.SIGNUP_SUBTYPE_AGREEMENT_NAME XFR_SGNP_STYPE_AGR_NM,MASTER_CONTRACT_XFR.CONTRACT_NUMBER XFR_CTR_NBR,CONTRACT_DETAIL_XFR.CONTRACT_SUFFIX_NUMBER XFR_CTR_SFX_NBR,CONTRACT_DETAIL.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_DETAIL.CREATION_DATE CRE_DT,CONTRACT_DETAIL.CREATION_USER_NAME CRE_USER_NM,CONTRACT_DETAIL.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_DETAIL.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,CONTRACT_DETAIL.supplemental_contract_suffix_identification SUPL_CTR_SFX_ID,SIGNUP_SUB_CATEGORY.op,5 AS TBL_PRIORITYFROM "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORYLEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP SIGNUP ON (SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".MASTER_CONTRACT MASTER_CONTRACT ON (SIGNUP.SIGNUP_IDENTIFIER = MASTER_CONTRACT.SIGNUP_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_TYPE SIGNUP_TYPE ON (SIGNUP_TYPE.SIGNUP_TYPE_CODE = SIGNUP.SIGNUP_TYPE_CODE) JOIN "fsa-{env}-ccms-cdc".CONTRACT_DETAIL CONTRACT_DETAIL ON (MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_DETAIL CONTRACT_DETAIL_PR ON (CONTRACT_DETAIL.PRIOR_CONTRACT_DETAIL_IDENTIFIER = CONTRACT_DETAIL_PR.CONTRACT_DETAIL_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".MASTER_CONTRACT MASTER_CONTRACT_PR ON (CONTRACT_DETAIL_PR.CONTRACT_IDENTIFIER = MASTER_CONTRACT_PR.CONTRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP SIGNUP_PR ON (SIGNUP_PR.SIGNUP_IDENTIFIER = MASTER_CONTRACT_PR.SIGNUP_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_TYPE SIGNUP_TYPE_PR ON (SIGNUP_TYPE_PR.SIGNUP_TYPE_CODE = SIGNUP_PR.SIGNUP_TYPE_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY SIGNUP_SUB_CATEGORY_PR ON (SIGNUP_SUB_CATEGORY_PR.SIGNUP_SUB_CATEGORY_CODE = SIGNUP_PR.SIGNUP_SUB_CATEGORY_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_DETAIL CONTRACT_DETAIL_XFR ON (CONTRACT_DETAIL.TRANSFER_CONTRACT_DETAIL_IDENTIFIER = CONTRACT_DETAIL_XFR.CONTRACT_DETAIL_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".MASTER_CONTRACT MASTER_CONTRACT_XFR ON (CONTRACT_DETAIL_XFR.CONTRACT_IDENTIFIER = MASTER_CONTRACT_XFR.CONTRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP SIGNUP_XFR ON (SIGNUP_XFR.SIGNUP_IDENTIFIER = MASTER_CONTRACT_XFR.SIGNUP_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_TYPE SIGNUP_TYPE_XFR ON (SIGNUP_TYPE_XFR.SIGNUP_TYPE_CODE = SIGNUP_XFR.SIGNUP_TYPE_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY SIGNUP_SUB_CATEGORY_XFR ON (SIGNUP_SUB_CATEGORY_XFR.SIGNUP_SUB_CATEGORY_CODE = SIGNUP_XFR.SIGNUP_SUB_CATEGORY_CODE)WHERE SIGNUP_SUB_CATEGORY.op <> 'D') STG_ALL) STG_UNQWHERE row_num_part = 1AND CONTRACT_DETAIL.dart_filedate BETWEEN DATE '{ETL_START_DATE}' AND DATE '{ETL_END_DATE}'
UNIONSELECT DISTINCTNULL ADM_ST_FSA_CD,NULL ADM_CNTY_FSA_CD,NULL SGNP_TYPE_NM,NULL SGNP_SUB_CAT_NM,NULL SGNP_NBR,NULL SGNP_STYPE_AGR_NM,NULL CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,CONTRACT_DETAIL.CONTRACT_ACTIVITY_TYPE_CODE CTR_ACTV_TYPE_CD,CONTRACT_DETAIL.PRIOR_CONTRACT_DETAIL_IDENTIFIER PR_CTR_DET_ID,CONTRACT_DETAIL.CONTRACT_IDENTIFIER CTR_ID,CONTRACT_DETAIL.CONTRACT_DESCRIPTION CTR_DESC,CONTRACT_DETAIL.EFFECTIVE_START_DATE EFF_STRT_DT,CONTRACT_DETAIL.EFFECTIVE_END_DATE EFF_END_DT,CONTRACT_DETAIL.APPROVED_DATE APRV_DT,CONTRACT_DETAIL.OTHER_ACTIVITY_REASON_DESCRIPTION OT_ACTV_RSN_DESC,CONTRACT_DETAIL.TRANSFER_CONTRACT_DETAIL_IDENTIFIER XFR_CTR_DET_ID,CONTRACT_DETAIL.PAYMENT_CONTRACT_SUFFIX_NUMBER PYMT_CTR_SFX_NBR,CONTRACT_DETAIL.PRACTICE_MAINTENANCE_RESPONSIBILITY_CODE PRAC_MNT_RESP_CD,CONTRACT_DETAIL.CONTRACT_ACREAGE CTR_ACRG,CONTRACT_DETAIL.PAYABLE_ACREAGE PYBL_ACRG,CONTRACT_DETAIL.EXPIRED_ACREAGE EXPR_ACRG,CONTRACT_DETAIL.PRODUCER_SIGNED_DATE PRDR_SGN_DT,CONTRACT_DETAIL.CP0_DOCUMENT_UPDATE_RECEIVED_INDICATOR CP0_DOC_UPD_RCV_IND,CONTRACT_DETAIL.forestry_services_responsibilities_completed_code FRST_SVC_RESP_CPLT_CD,CONTRACT_DETAIL.ANNUAL_WEIGHTED_AVERAGE_MAINTENANCE_AMOUNT_PER_ACRE ANL_WT_AVG_MNT_AMT_PER_ACRE,CONTRACT_DETAIL.ANNUAL_WEIGHTED_AVERAGE_SOIL_RENTAL_AMOUNT_PER_ACRE ANL_WT_AVG_SOIL_RNT_AMT_ACRE,CONTRACT_DETAIL.MIGRATION_REFERENCE_IDENTIFICATION MIGR_REF_ID,CONTRACT_DETAIL.ANNUAL_RENTAL_AMOUNT_PER_ACRE ANL_RNT_AMT_PER_ACRE,CONTRACT_DETAIL.Contract_Migration_Code CTR_MIGR_CD,CONTRACT_DETAIL.CONTRACT_CORRECTION_INDICATOR CTR_COR_IND,CONTRACT_DETAIL.MANUAL_RATE_CALCULATION_INDICATOR MNL_RT_CALC_IND,CONTRACT_DETAIL.Contract_Annual_Payment_Amount CTR_ANL_PYMT_AMT,CONTRACT_DETAIL.ANNUAL_WEIGHTED_AVERAGE_INCENTIVE_AMOUNT_PER_ACRE ANL_WT_AVG_INCTV_AMT_ACRE,CONTRACT_DETAIL.ANNUAL_MAXIMUM_PAYMENT_AMOUNT_PER_ACRE ANL_MAX_PYMT_AMT_PER_ACRE,CONTRACT_DETAIL.dafp_approved_date DAFP_APRV_DT,CONTRACT_DETAIL.NOTIFICATION_LETTER_SENT_DATE NTFY_LTR_SENT_DT,CONTRACT_DETAIL.VALID_CONTRACT_INDICATOR VLD_CTR_INDICAOR,CONTRACT_DETAIL.INVALID_CONTRACT_DATE IVLD_CTR_DT,NULL PR_ADM_ST_FSA_CD,NULL PR_ADM_CNTY_FSA_CD,NULL PR_SGNP_TYPE_NM,NULL PR_SGNP_SUB_CAT_NM,NULL PR_SGNP_NBR,NULL PR_SGNP_STYPE_AGR_NM,NULL PR_CTR_NBR,NULL PR_CTR_SFX_NBR,NULL XFR_ADM_ST_FSA_CD,NULL XFR_ADM_CNTY_FSA_CD,NULL XFR_SGNP_TYPE_NM,NULL XFR_SGNP_SUB_CAT_NM,NULL XFR_SGNP_NBR,NULL XFR_SGNP_STYPE_AGR_NM,NULL XFR_CTR_NBR,NULL XFR_CTR_SFX_NBR,CONTRACT_DETAIL.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_DETAIL.CREATION_DATE CRE_DT,CONTRACT_DETAIL.CREATION_USER_NAME CRE_USER_NM,CONTRACT_DETAIL.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_DETAIL.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,CONTRACT_DETAIL.supplemental_contract_suffix_identification SUPL_CTR_SFX_ID,'D' CDC_OPER_CD,1 AS row_num_partFROM "fsa-{env}-ccms-cdc".CONTRACT_DETAILWHERE CONTRACT_DETAIL.op = 'D'